package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatWithHeaderCommentsTest {

    @Test
    void testWithHeaderComments_nullComments() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeaderComments((Object[]) null);
        assertNotNull(result);
        assertNotSame(format, result);
        assertNull(result.getHeaderComments());
    }

    @Test
    void testWithHeaderComments_emptyComments() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeaderComments();
        assertNotNull(result);
        assertNotSame(format, result);
        assertNull(result.getHeaderComments());
    }

    @Test
    void testWithHeaderComments_singleComment() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeaderComments("comment1");
        assertNotNull(result);
        assertNotSame(format, result);
        String[] comments = result.getHeaderComments();
        assertNotNull(comments);
        assertEquals(1, comments.length);
        assertEquals("comment1", comments[0]);
    }

    @Test
    void testWithHeaderComments_multipleComments() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeaderComments("comment1", "comment2", "comment3");
        assertNotNull(result);
        assertNotSame(format, result);
        String[] comments = result.getHeaderComments();
        assertNotNull(comments);
        assertEquals(3, comments.length);
        assertArrayEquals(new String[] {"comment1", "comment2", "comment3"}, comments);
    }

    @Test
    void testWithHeaderComments_preservesOtherProperties() {
        CSVFormat format = CSVFormat.DEFAULT
                .withDelimiter(';')
                .withQuote('\'')
                .withQuoteMode(null)
                .withCommentMarker('#')
                .withEscape('\\')
                .withIgnoreSurroundingSpaces(true)
                .withIgnoreEmptyLines(false)
                .withRecordSeparator("\n")
                .withNullString("NULL")
                .withHeader("h1", "h2")
                .withSkipHeaderRecord(true)
                .withAllowMissingColumnNames(true)
                .withIgnoreHeaderCase(true)
                .withTrim(true)
                .withTrailingDelimiter(true)
                .withAutoFlush(true);

        CSVFormat result = format.withHeaderComments("headerComment");

        assertNotSame(format, result);
        assertEquals(';', result.getDelimiter());
        assertEquals(Character.valueOf('\''), result.getQuoteCharacter());
        assertNull(result.getQuoteMode());
        assertEquals(Character.valueOf('#'), result.getCommentMarker());
        assertEquals(Character.valueOf('\\'), result.getEscapeCharacter());
        assertTrue(result.getIgnoreSurroundingSpaces());
        assertFalse(result.getIgnoreEmptyLines());
        assertEquals("\n", result.getRecordSeparator());
        assertEquals("NULL", result.getNullString());
        assertArrayEquals(new String[] {"h1", "h2"}, result.getHeader());
        assertTrue(result.getSkipHeaderRecord());
        assertTrue(result.getAllowMissingColumnNames());
        assertTrue(result.getIgnoreHeaderCase());
        assertTrue(result.getTrim());
        assertTrue(result.getTrailingDelimiter());
        assertTrue(result.getAutoFlush());
        String[] comments = result.getHeaderComments();
        assertNotNull(comments);
        assertEquals(1, comments.length);
        assertEquals("headerComment", comments[0]);
    }
}
